script:
@keyframes commit-marquee {
	from { transform: translateX(0); }
	to { transform: translateX(-50%); }
}
.commit-marquee-track { animation: commit-marquee 30s linear infinite; }

@keyframes commit-float {
	0%, 100% { transform: translateY(0px); }
	50% { transform: translateY(-20px); }
}
.commit-blob { animation: commit-float 9s ease-in-out infinite; }
.commit-blob-slow { animation: commit-float 14s ease-in-out infinite; }

.js-reveal [data-reveal] {
	opacity: 0;
	transform: translateY(22px);
	transition: opacity 0.6s ease-out, transform 0.6s ease-out;
}
.js-reveal [data-reveal].in-view { opacity: 1; transform: translateY(0); }

@media (prefers-reduced-motion: reduce) {
	.commit-marquee-track, .commit-blob, .commit-blob-slow { animation: none; }
	.js-reveal [data-reveal] { opacity: 1; transform: none; transition: none; }
}
